VALUES
  ('generalpolice-94737317-moex-00242', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '中央法規標準法規定，命令之廢止由原發布機關為之。如命令之原發布機關業經中央政府組織改造而裁併 時，應由下列何機關為該命令之廢止？', '["如屬中央層級命令，由行政院為之；如屬地方層級命令，由該地方行政首長為之", "承受其業務之機關或其上級機關為之", "由司法院依統一解釋法令權限逕行宣告廢止", "由具命令備查權限之立法院依職權逕行宣告廢止"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00243', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依憲法訴訟法第52條規定，憲法法庭之判決宣告法律違憲且應失效者，該法律自判決生效日起失效。惟 憲法法庭依同法規定，得否判決宣告特定法律定期失效？', '["得宣告法律定期失效，但其所定期間，法律位階之法規範不得逾二年", "不得宣告法律定期失效，以維護憲法規範之最高性", "得宣告法律定期失效，但其所定期間，法律位階之法規範不得逾六個月", "不得宣告法律定期失效，應尊重立法者修法時程之自主安排"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00244', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '最高法院在某一判決中認為，由於法律規範有漏洞，基於規範意旨，應該將規範的適用範圍擴大到法條文 義未包含的範圍。此時最高法院使用的法學方法，最可能是下列何種方法？', '["歷史解釋", "類推適用", "目的性限縮", "目的性擴張"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00245', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依民法規定，下列有關成年監護之敘述，何者正確？', '["因精神耗弱致不能處理自己事務，尚能辨識意思表示效果之人，仍應為監護之宣告", "受輔助宣告之人為限制行為能力人，應全部準用限制行為能力人之規定", "監護人不限於一人，而得為多數", "受輔助宣告人仍具遺囑見證人之資格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00246', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '下列關於我國民法物權編取得時效之規定，何者正確？', '["所有權之取得時效不中斷", "以所有之意思，二十年間和平、公然、繼續占有他人未登記之不動產者，取得其所有權", "以所有之意思，五年間和平、公然、繼續占有他人之動產者，取得其所有權", "對於他人已登記之不動產，無法因取得時效完成，而取得該不動產之所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
